def _cosmos_mongo_db_database_to_nested(
    cosmos_mongo_db_database: CosmosMongoDBDatabase,
) -> CosmosMongoDBDatabaseNested:
    """Convert flat CosmosMongoDBDatabase to nested format."""
    attrs = CosmosMongoDBDatabaseAttributes()
    _populate_cosmos_mongo_db_database_attrs(attrs, cosmos_mongo_db_database)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        cosmos_mongo_db_database,
        _COSMOS_MONGO_DB_DATABASE_REL_FIELDS,
        CosmosMongoDBDatabaseRelationshipAttributes,
    )
    return CosmosMongoDBDatabaseNested(
        guid=cosmos_mongo_db_database.guid,
        type_name=cosmos_mongo_db_database.type_name,
        status=cosmos_mongo_db_database.status,
        version=cosmos_mongo_db_database.version,
        create_time=cosmos_mongo_db_database.create_time,
        update_time=cosmos_mongo_db_database.update_time,
        created_by=cosmos_mongo_db_database.created_by,
        updated_by=cosmos_mongo_db_database.updated_by,
        classifications=cosmos_mongo_db_database.classifications,
        classification_names=cosmos_mongo_db_database.classification_names,
        meanings=cosmos_mongo_db_database.meanings,
        labels=cosmos_mongo_db_database.labels,
        business_attributes=cosmos_mongo_db_database.business_attributes,
        custom_attributes=cosmos_mongo_db_database.custom_attributes,
        pending_tasks=cosmos_mongo_db_database.pending_tasks,
        proxy=cosmos_mongo_db_database.proxy,
        is_incomplete=cosmos_mongo_db_database.is_incomplete,
        provenance_type=cosmos_mongo_db_database.provenance_type,
        home_id=cosmos_mongo_db_database.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _cosmos_mongo_db_database_from_nested(
    nested: CosmosMongoDBDatabaseNested,
) -> CosmosMongoDBDatabase:
    """Convert nested format to flat CosmosMongoDBDatabase."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else CosmosMongoDBDatabaseAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _COSMOS_MONGO_DB_DATABASE_REL_FIELDS,
        CosmosMongoDBDatabaseRelationshipAttributes,
    )
    return CosmosMongoDBDatabase(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_cosmos_mongo_db_database_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _cosmos_mongo_db_database_to_nested_bytes(
    cosmos_mongo_db_database: CosmosMongoDBDatabase, serde: Serde
) -> bytes:
    """Convert flat CosmosMongoDBDatabase to nested JSON bytes."""
    return serde.encode(_cosmos_mongo_db_database_to_nested(cosmos_mongo_db_database))


def _cosmos_mongo_db_database_from_nested_bytes(
    data: bytes, serde: Serde
) -> CosmosMongoDBDatabase:
    """Convert nested JSON bytes to flat CosmosMongoDBDatabase."""
    nested = serde.decode(data, CosmosMongoDBDatabaseNested)
    return _cosmos_mongo_db_database_from_nested(nested)


